        "platform_item1": "Enterprise security — CSRF, rate limiting, TOTP 2FA, WebAuthn passkeys, CSP nonces, CORS allowlist, and Form Request validation",
        "platform_item10": "Federation — four protocol adapters live: Nexus (native), Komunitin (all 15 endpoints), Credit Commons (11 endpoints, CEN-compatible mutual credit), and TimeOverflow; two-way sync across 9 entity types, event-driven push, and reputation portability",
        "platform_item11": "Payments layer — Stripe for subscriptions, donations, marketplace (Connect), and identity verification, with idempotent webhook handling",
        "platform_item2": "GDPR compliance — data requests, consent management, breach tracking, and audit log",
        "platform_item3": "Fraud and abuse detection — automated suspicious activity alerts and content moderation",
        "platform_item4": "WCAG 2.1 AA accessibility compliance",
        "platform_item5": "11 languages — English, Irish, German, French, Italian, Portuguese, Spanish, Dutch, Polish, Japanese, and Arabic (with full RTL support)",
